var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"짠! 도착!","JPN":"ジャーン！　到着！","ENG":"Ta-da! I'm here!","TWN":"鏘！到達！"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"내가 좀 늦었지? 고등부는 시험기간이라고 연장수업을 시켜서 말이야.","JPN":"待たせちゃったね。高等部は\\n試験期間だから補修授業があってさ。","ENG":"Sorry I'm a bit late. They extended our classes in high school since it's exam season.","TWN":"我來晚了嗎？高中部在考試期間都會晚下課。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"얼른 부실 청소를......","JPN":"さっさとサークル室の掃除を……","ENG":"I'll start cleaning the room...","TWN":"我得快點打掃才行……"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"응?","JPN":"えっ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BEAR_EXTRA_NULL_NULL","text":{"KOREA":"......크르릉?!","JPN":"……グルル！？","ENG":"Grrr?!","TWN":"……嗷唔？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"으아악?!!","JPN":"うわっ！？","ENG":"Ahhh?!","TWN":"呀啊啊？！！"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"고, 곰이다! 곰이 빗자루질을 하고 있어?!","JPN":"ク、クマ！　クマがホウキを持ってる！？","ENG":"A b-bear! A bear is sweeping the floor?!","TWN":"有、有熊啊！熊竟然在用掃把掃地？！"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아, 호진 언니! 오셨어요?","JPN":"あ、マユミさん！　遅かったですね？","ENG":"Oh, Hojin! You're here.","TWN":"啊，鎬眞姐姐！妳來了啊？"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"하림아 도망쳐! 곰이야! 곰이라고!","JPN":"ウサギちゃん、逃げて！　クマよ、クマが出た！","ENG":"Harim, run! It's a bear! A bear!","TWN":"夏琳快逃！熊！有熊啊！"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아, 괜찮아요. 저건 고미가 답답하다고 해서 원래 모습으로 잠시 바꿔놓은 거 거든요.","JPN":"あ、大丈夫ですよ。クマたんが息苦しいって言うから、少しの間だけ元の姿に戻してるんです。","ENG":"Oh, it's okay. Teddy's been feeling a bit stuffy, so I just turned her back to her original form for a bit.","TWN":"啊，沒事啦。那是咕美熊熊說太無聊了，所以想暫時變回原來的樣子。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"자, 이제 휴식시간은 끝! 돌아와!","JPN":"さぁ、休憩時間は終わり！　戻ってきて！","ENG":"Alright, that's the end of your break! Come back!","TWN":"好了，休息時間結束了！回來吧！"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"BEAR_SUMMON_NULL_NULL","text":{"KOREA":"삑! 삐삑!","JPN":"ピッ！　ピッ！","ENG":"Beep! Be-beep!","TWN":"嗶！嗶嗶！"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"BEAR_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"이, 이게...... 그 무시무시한 곰이었다고?","JPN":"こ、これが……あの恐ろしいクマだったの？","ENG":"Th-this... was that scary looking bear?","TWN":"那、那是……剛剛那隻可怕的熊？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"BEAR_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그렇다. 고미 대원은 원래 버추얼 월드에서 온 풍부한 실전 경험을 가진 물리 마법사로서 베테랑 솔저인 나도 많은 지도편달을 받고 있지.","JPN":"そうだ。クマたん隊員はバーチャルワールドから来た豊富な実戦経験を持つ\\n物理魔法使いで、ベテランソルジャーの本官も多くの指導を受けている。","ENG":"That's right. Teddy is a seasoned physical-type wizard from the virtual world. Even I have a lot to learn from Teddy despite being a veteran soldier.","TWN":"是啊。咕美熊熊隊員是來自虛擬世界，擁有豐富實戰經驗的物理法師，就是身為老兵的我也受到牠很多指導和鞭策呢。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"BEAR_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"버추얼 월드......?! 정말로 그런 게 있어?","JPN":"バーチャルワールド……！？　本当にそんなものがあるの？","ENG":"The virtual world?! That really exists?","TWN":"虛擬世界……？！真的有這種東西嗎？"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"BEAR_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"정확히는 <color=#ffd34c>시계 속 동물원</color>이에요. 소림이는 이 어플을 자꾸 이상한 이름으로 부른다니까.","JPN":"正確には<color=#ffd34c>時計の中の動物園</color>です。\\nミズキったら、このアプリをいつも変な名前で呼ぶんだから！","ENG":"To be exact, it's a <color=#ffd34c>zoo inside my Watch</color>. Sorim just made up a weird name for this application.","TWN":"正確來說是<color=#ffd34c>鐘錶中的動物園</color>，但蕭林總一直用奇怪的名字稱呼這個應用程式。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"하, 하지만 그게 더 멋있는걸......","JPN":"し、しかしその方がもっとカッコイイ……","ENG":"B-but it sounds a lot cooler...","TWN":"但、但是那個名字更帥啊……"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};